import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
} from "../components/ui/card";
import { Button } from "../components/ui/button";
import { authService, User } from "../services/api";
import SmartEnergyChatbot from "../components/SmartEnergyChatbot";

const Dashboard: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [showUserProfile, setShowUserProfile] = useState(false);
  const navigate = useNavigate();



  useEffect(() => {
    const fetchUser = async () => {
      try {
        const token = localStorage.getItem("access_token");
        if (!token) {
          navigate("/login");
          return;
        }

        const userData = await authService.getCurrentUser();
        setUser(userData);
      } catch (error) {
        console.error("Failed to fetch user:", error);
        navigate("/login");
      } finally {
        setLoading(false);
      }
    };

    fetchUser();
  }, [navigate]);

  const handleLogout = () => {
    authService.logout();
    navigate("/login");
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-muted-foreground">Loading...</p>
        </div>
      </div>
    );
  }

  if (!user) return null;

  return (
    <div className="min-h-screen bg-gradient-to-br from-green-50 via-blue-50 to-indigo-100 relative overflow-hidden">
      {/* Animated Background */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute -top-4 -left-4 w-72 h-72 bg-green-200 rounded-full mix-blend-multiply filter blur-xl opacity-30 animate-pulse"></div>
        <div className="absolute top-1/4 -right-4 w-72 h-72 bg-blue-200 rounded-full mix-blend-multiply filter blur-xl opacity-30 animate-pulse animation-delay-2000"></div>
        <div className="absolute -bottom-8 left-1/3 w-72 h-72 bg-indigo-200 rounded-full mix-blend-multiply filter blur-xl opacity-30 animate-pulse animation-delay-4000"></div>
      </div>

      {/* Navigation */}
      <nav className="bg-white/90 backdrop-blur-md shadow-lg border-b border-green-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center space-x-3 cursor-pointer hover:opacity-80 transition-opacity">
              <div className="w-8 h-8 bg-gradient-to-br from-green-500 to-blue-600 rounded-lg flex items-center justify-center">
                <span className="text-white font-bold text-lg">⚡</span>
              </div>
              <h1 className="text-2xl font-bold bg-gradient-to-r from-green-600 to-blue-600 bg-clip-text text-transparent">
                WattWise
              </h1>
            </div>
            <div className="flex items-center space-x-4">
              <span className="text-sm text-gray-700 font-medium">
                Welcome, {user.username}
              </span>
              {/* User Profile Button */}
              <Button
                variant="outline"
                onClick={() => setShowUserProfile(true)}
                className="border-blue-200 text-blue-700 hover:bg-blue-50 flex items-center space-x-2"
              >
                <div className="w-6 h-6 bg-gradient-to-br from-green-400 to-blue-500 rounded-full flex items-center justify-center">
                  <span className="text-white font-bold text-xs">
                    {user.username[0].toUpperCase()}
                  </span>
                </div>
                <span>Profile</span>
              </Button>
              <Button
                variant="outline"
                onClick={handleLogout}
                className="border-green-200 text-green-700 hover:bg-green-50"
              >
                Logout
              </Button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
        <div className="px-4 py-6 sm:px-0 space-y-6">
          {/* Welcome Card */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
          >
            <Card className="bg-gradient-to-br from-white/80 to-green-50 backdrop-blur-lg border-green-200 shadow-xl">
              <CardHeader>
                <CardTitle className="text-3xl font-bold bg-gradient-to-r from-green-600 to-blue-600 bg-clip-text text-transparent">
                  Welcome to WattWise
                </CardTitle>
                <CardDescription className="text-lg text-gray-600">
                  Your smart energy management platform is ready to help you save
                  energy and reduce costs.
                </CardDescription>
              </CardHeader>
            </Card>
          </motion.div>

          {/* Quick Actions */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.4 }}
          >
            <Card className="bg-white/80 backdrop-blur-lg border-gray-200 shadow-xl">
              <CardHeader>
                <CardTitle>Quick Actions</CardTitle>
                <CardDescription>
                  Access frequently used features quickly
                </CardDescription>
              </CardHeader>
              <CardContent>
                <div className="flex flex-wrap gap-3 justify-between">
                  <Button
                    onClick={() => navigate('/Addroom')}
                    className="flex-1 min-w-0 px-4 py-3 bg-green-100 text-green-700 hover:bg-green-200 border-green-200 transition-all duration-200 hover:scale-105 hover:shadow-md"
                    variant="outline"
                  >
                    <span className="mr-2 text-lg">⚡</span>
                    <span className="font-medium">Add Room</span>
                  </Button>
                  <Button
                    onClick={() => navigate('/log-usage')}
                    className="flex-1 min-w-0 px-4 py-3 bg-blue-100 text-blue-700 hover:bg-blue-200 border-blue-200 transition-all duration-200 hover:scale-105 hover:shadow-md"
                    variant="outline"
                  >
                    <span className="mr-2 text-lg">📝</span>
                    <span className="font-medium">Log Usage</span>
                  </Button>
                  <Button
                    className="flex-1 min-w-0 px-4 py-3 bg-yellow-100 text-yellow-700 hover:bg-yellow-200 border-yellow-200 transition-all duration-200 hover:scale-105 hover:shadow-md"
                    variant="outline"
                  >
                    <span className="mr-2 text-lg">🎯</span>
                    <span className="font-medium">Set Goals</span>
                  </Button>
                  <Button
                    className="flex-1 min-w-0 px-4 py-3 bg-purple-100 text-purple-700 hover:bg-purple-200 border-purple-200 transition-all duration-200 hover:scale-105 hover:shadow-md"
                    variant="outline"
                  >
                    <span className="mr-2 text-lg">⚙️</span>
                    <span className="font-medium">Manage Appliances</span>
                  </Button>
                </div>
              </CardContent>
            </Card>
          </motion.div>

          {/* Energy Analytics Dashboard */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.6 }}
            className="grid grid-cols-1 md:grid-cols-2 gap-6"
          >
            {/* Weekly Usage Chart */}
            <Card className="bg-gradient-to-br from-white/80 to-green-50 backdrop-blur-lg border-green-200 shadow-xl">
              <CardHeader>
                <CardTitle className="text-xl font-bold text-green-700 flex items-center">
                  <span className="mr-2">📊</span>
                  Weekly Usage
                </CardTitle>
                <CardDescription>
                  Your energy consumption over the past 7 days
                </CardDescription>
              </CardHeader>
              <CardContent>
                <div className="space-y-3">
                  {['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'].map((day, index) => {
                    const usage = Math.random() * 15 + 5; // Mock data
                    const percentage = (usage / 20) * 100;
                    return (
                      <div key={day} className="flex items-center justify-between">
                        <span className="text-sm font-medium text-gray-700 w-8">{day}</span>
                        <div className="flex-1 mx-3">
                          <div className="w-full bg-gray-200 rounded-full h-2">
                            <motion.div
                              className="bg-gradient-to-r from-green-400 to-blue-500 h-2 rounded-full"
                              initial={{ width: 0 }}
                              animate={{ width: `${percentage}%` }}
                              transition={{ duration: 0.8, delay: index * 0.1 }}
                            />
                          </div>
                        </div>
                        <span className="text-sm font-semibold text-gray-900 w-12 text-right">
                          {usage.toFixed(1)} kWh
                        </span>
                      </div>
                    );
                  })}
                </div>
              </CardContent>
            </Card>

            {/* Monthly Savings */}
            <Card className="bg-gradient-to-br from-white/80 to-blue-50 backdrop-blur-lg border-blue-200 shadow-xl">
              <CardHeader>
                <CardTitle className="text-xl font-bold text-blue-700 flex items-center">
                  <span className="mr-2">💰</span>
                  Monthly Savings
                </CardTitle>
                <CardDescription>
                  Track your energy cost savings
                </CardDescription>
              </CardHeader>
              <CardContent>
                <div className="text-center space-y-4">
                  <div className="relative w-32 h-32 mx-auto">
                    <div className="absolute inset-0 rounded-full border-8 border-gray-200"></div>
                    <motion.div
                      className="absolute inset-0 rounded-full border-8 border-green-500 border-r-transparent"
                      initial={{ rotate: 0 }}
                      animate={{ rotate: 270 }}
                      transition={{ duration: 1.5, ease: "easeInOut" }}
                      style={{ transformOrigin: '50% 50%' }}
                    />
                    <div className="absolute inset-0 flex items-center justify-center">
                      <div className="text-center">
                        <div className="text-2xl font-bold text-green-600">₹847</div>
                        <div className="text-xs text-gray-500">saved</div>
                      </div>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between items-center text-sm">
                      <span className="text-gray-600">Previous Month:</span>
                      <span className="font-semibold">₹2,456</span>
                    </div>
                    <div className="flex justify-between items-center text-sm">
                      <span className="text-gray-600">Current Month:</span>
                      <span className="font-semibold text-green-600">₹1,609</span>
                    </div>
                    <div className="text-center text-xs text-green-600 font-medium">
                      ↓ 34.5% reduction
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          </motion.div>

          {/* Top Energy Consumers */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.8 }}
          >
            <Card className="bg-gradient-to-br from-white/80 to-orange-50 backdrop-blur-lg border-orange-200 shadow-xl">
              <CardHeader>
                <CardTitle className="text-xl font-bold text-orange-700 flex items-center">
                  <span className="mr-2">⚡</span>
                  Top Energy Consumers
                </CardTitle>
                <CardDescription>
                  Appliances using the most energy this month
                </CardDescription>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  {[
                    { name: 'Air Conditioner', room: 'Living Room', usage: 145.7, cost: 1835 },
                    { name: 'Water Heater', room: 'Bathroom', usage: 89.3, cost: 1124 },
                    { name: 'Refrigerator', room: 'Kitchen', usage: 67.2, cost: 846 },
                    { name: 'Washing Machine', room: 'Utility', usage: 34.8, cost: 438 },
                  ].map((appliance, index) => (
                    <motion.div
                      key={appliance.name}
                      initial={{ opacity: 0, x: -20 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ duration: 0.5, delay: 0.9 + index * 0.1 }}
                      className="flex items-center justify-between p-3 bg-white/60 rounded-lg border border-orange-100 hover:bg-white/80 transition-colors"
                    >
                      <div className="flex items-center space-x-3">
                        <div className="w-8 h-8 bg-gradient-to-br from-orange-400 to-red-500 rounded-full flex items-center justify-center text-white font-bold text-sm">
                          {index + 1}
                        </div>
                        <div>
                          <p className="font-semibold text-gray-900">{appliance.name}</p>
                          <p className="text-sm text-gray-600">{appliance.room}</p>
                        </div>
                      </div>
                      <div className="text-right">
                        <p className="font-bold text-orange-600">{appliance.usage} kWh</p>
                        <p className="text-sm text-gray-600">₹{appliance.cost}</p>
                      </div>
                    </motion.div>
                  ))}
                </div>
              </CardContent>
            </Card>
          </motion.div>
        </div>
      </main>

      {/* Floating Action Buttons */}
      <div className="fixed bottom-24 right-6 z-40">
        {/* Add Room Button */}
        <button
          onClick={() => navigate('/Addroom?add=1')}
          className="h-14 w-14 rounded-full bg-gradient-to-br from-purple-500 to-pink-600 text-white shadow-xl border border-white/50 flex items-center justify-center text-3xl hover:scale-105 transition-transform"
          aria-label="Add Room"
        >
          +
        </button>
      </div>

      {/* Smart Energy Chatbot */}
      <SmartEnergyChatbot />
    </div>
  );
};

export default Dashboard;
